+    function covFromPoints(batch, mean) {
+      if (!batch.length) return [1,0,0,1];
+      const n = batch.length;
+      let sxx=0, sxy=0, syy=0;
+      for (const p of batch) {
+        const dx = p.x - mean.x;
+        const dy = p.y - mean.y;
+        sxx += dx*dx;
+        sxy += dx*dy;
+        syy += dy*dy;
+      }
+      const denom = Math.max(1, n-1);
+      return [sxx/denom, sxy/denom, sxy/denom, syy/denom];
+    }
